import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import Cookies from "js-cookie";
import { toast } from "react-toastify";
import Toast from "../components/Toast";
import copy from "copy-to-clipboard";
import dayjs from "dayjs";

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api";

function UserDetails() {
  const { userId } = useParams();
  const navigate = useNavigate();

  const [user, setUser] = useState(null);
  const [payments, setPayments] = useState([]);
  const [supportRequest, setSupportRequest] = useState(null);
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState("profile");

  // =================== COPY TO CLIPBOARD ===================
  const handleCopy = (text, label) => {
    if (copy(text)) toast.success(`${label} copied to clipboard`);
    else toast.error(`Failed to copy ${label}`);
  };

  // =================== FETCH USER & PAYMENTS ===================
  useEffect(() => {
    const token = Cookies.get("adminToken");
    if (!token) {
      navigate("/");
      return;
    }

    setLoading(true);

    axios
      .get(`${API_BASE_URL}/users/${userId}`, {
        headers: { Authorization: `Bearer ${token}` },
      })
      .then((res) => {
        if (res.data.success) setUser(res.data.data);
        else toast.error(res.data.error || "Failed to fetch user");
      })
      .catch((err) =>
        toast.error(err.response?.data?.error || "Error fetching user"),
      );

    axios
      .get(`${API_BASE_URL}/users/${userId}/payments`, {
        headers: { Authorization: `Bearer ${token}` },
      })
      .then((res) => {
        if (res.data.success) setPayments(res.data.data);
        else toast.error(res.data.error || "Failed to fetch payments");
      })
      .catch((err) =>
        toast.error(err.response?.data?.error || "Error fetching payments"),
      )
      .finally(() => setLoading(false));
  }, [userId, navigate]);

  // =================== FETCH SUPPORTS FOR USER ===================
  useEffect(() => {
    const token = Cookies.get("adminToken");
    if (!token) return;

    axios
      .get(`${API_BASE_URL}/users/supports/${userId}`, {
        headers: { Authorization: `Bearer ${token}` },
      })
      .then((res) => {
        if (res.data.success) setSupportRequest(res.data.data);
        else toast.error(res.data.error || "Failed to fetch support requests");
      })
      .catch((err) =>
        toast.error(
          err.response?.data?.error || "Error fetching support requests",
        ),
      );
  }, [userId]);

  if (loading) return <div className="text-center mt-5">Loading...</div>;
  if (!user) return <div className="text-center mt-5">No user found</div>;

  return (
    <div className="container mt-3">
      <Toast />

      {/* Back Button */}
      <div className="row mb-3">
        <div className="col">
          <i
            className="fa fa-arrow-left mt-2"
            style={{ cursor: "pointer" }}
            onClick={() => navigate(-1)}
          ></i>
        </div>
      </div>

      {/* Header & Tabs */}
      <div className="row g-3 mb-3">
        <div className="col-md-4">
          <h4 className="fw-bold mb-0">User Profile</h4>
        </div>

        <div className="col-md-8 d-flex justify-content-md-end">
          <ul className="nav nav-tabs">
            <li className="nav-item">
              <button
                className={`nav-link ${
                  activeTab === "profile" ? "active" : ""
                }`}
                onClick={() => setActiveTab("profile")}
              >
                Profile
              </button>
            </li>

            <li className="nav-item">
              <button
                className={`nav-link ${
                  activeTab === "payments" ? "active" : ""
                }`}
                onClick={() => setActiveTab("payments")}
              >
                Payments
              </button>
            </li>
            <li className="nav-item">
              <button
                className={`nav-link ${activeTab === "support" ? "active" : ""}`}
                onClick={() => setActiveTab("support")}
              >
                Support
              </button>
            </li>
          </ul>
        </div>
      </div>

      {/* ================= PROFILE TAB ================= */}
      {activeTab === "profile" && (
        <div className="mb-4">
          {/* Personal Information */}
          <div className="p-3 rounded bg-body border mb-4">
            <h5 className="fw-semibold mb-3">
              <i className="fa-solid fa-circle-user"></i> Personal Information
            </h5>

            <div className="row g-3">
              <div className="col-md-4">
                <small className="text-muted">
                  <i className="fa-solid fa-user text-secondary"></i> Name
                </small>
                <h6>
                  {user.prefix} {user.fullName}
                  <i
                    className="fa-solid fa-copy ms-1"
                    style={{ cursor: "pointer" }}
                    onClick={() => handleCopy(user.fullName, "Name")}
                  ></i>
                </h6>
              </div>

              <div className="col-md-4">
                <small className="text-muted">
                  <i className="fa-solid fa-envelope text-warning"></i> Email
                </small>
                <h6>
                  {user.email}
                  <i
                    className="fa-solid fa-copy ms-1"
                    style={{ cursor: "pointer" }}
                    onClick={() => handleCopy(user.email, "Email")}
                  ></i>
                </h6>
              </div>

              <div className="col-md-4">
                <small className="text-muted">
                  <i className="fa-solid fa-phone text-success"></i> Phone
                </small>
                <h6>
                  {user.phone}
                  <i
                    className="fa-solid fa-copy ms-1"
                    style={{ cursor: "pointer" }}
                    onClick={() => handleCopy(user.phone, "Phone")}
                  ></i>
                </h6>
              </div>
            </div>
          </div>

          {/* Related Employee */}
          {user.employeeId && (
            <div className="p-3 rounded bg-body border mb-4">
              <h5 className="fw-semibold mb-3">
                <i className="fa-solid fa-briefcase"></i> Related Employee
              </h5>

              <div className="row g-3">
                <div className="col-md-4">
                  <small className="text-muted">
                    <i className="fa-solid fa-user text-secondary"></i> Name
                  </small>
                  <h6>
                    {user.employeeName}
                    <i
                      className="fa-solid fa-copy ms-1"
                      style={{ cursor: "pointer" }}
                      onClick={() =>
                        handleCopy(user.employeeName, "Employee Name")
                      }
                    ></i>
                  </h6>
                </div>

                <div className="col-md-4">
                  <small className="text-muted">
                    <i className="fa-solid fa-envelope text-warning"></i> Email
                  </small>
                  <h6>
                    {user.employeeEmail || "N/A"}
                    {user.employeeEmail && (
                      <i
                        className="fa-solid fa-copy ms-1"
                        style={{ cursor: "pointer" }}
                        onClick={() =>
                          handleCopy(user.employeeEmail, "Employee Email")
                        }
                      ></i>
                    )}
                  </h6>
                </div>

                <div className="col-md-4">
                  <small className="text-muted">
                    <i className="fa-solid fa-phone text-success"></i> Phone
                  </small>
                  <h6>
                    {user.employeePhone || "N/A"}
                    {user.employeePhone && (
                      <i
                        className="fa-solid fa-copy ms-1"
                        style={{ cursor: "pointer" }}
                        onClick={() =>
                          handleCopy(user.employeePhone, "Employee Phone")
                        }
                      ></i>
                    )}
                  </h6>
                </div>
              </div>
            </div>
          )}

          {/* User Source / Status */}
          <div className="p-3 rounded bg-body border mb-4">
            <h5 className="fw-semibold mb-3">
              <i className="fa-solid fa-info-circle"></i> Other Information
            </h5>

            <div className="row g-3">
              <div className="col-md-6">
                <small className="text-muted">
                  <i className="fa-solid fa-hashtag text-secondary"></i> Status
                </small>
                <h6>
                  <span
                    className={`badge ${
                      user.status?.toLowerCase() === "client"
                        ? "bg-success"
                        : "bg-secondary"
                    }`}
                  >
                    {user.status}
                  </span>
                </h6>
              </div>

              <div className="col-md-6">
                <small className="text-muted">
                  <i className="fa-solid fa-globe text-info"></i> Source
                </small>
                <h6>{user.source || "N/A"}</h6>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ================= PAYMENTS TAB ================= */}
      {activeTab === "payments" && (
        <div className="card">
          <div className="card-body">
            <h5 className="card-title">Payments</h5>

            {payments.length > 0 ? (
              <div className="table-responsive rounded">
                <table className="table table-striped table-hover small">
                  <thead className="table-dark">
                    <tr>
                      <th>ID</th>
                      <th>Total</th>
                      <th>Paid</th>
                      <th>Remaining</th>
                      <th>Method</th>
                      <th>Status</th>
                      <th>Transaction ID</th>
                      <th>Payment Date</th>
                    </tr>
                  </thead>
                  <tbody>
                    {payments.map((p) => (
                      <tr key={p.id}>
                        <td style={{ minWidth: "50px" }}>{p.id}</td>
                        <td style={{ minWidth: "120px" }}>{p.totalAmount}</td>
                        <td style={{ minWidth: "120px" }}>{p.paidAmount}</td>
                        <td style={{ minWidth: "130px" }}>
                          {p.remainingAmount}
                        </td>
                        <td style={{ minWidth: "140px" }}>{p.paymentMethod}</td>
                        <td style={{ minWidth: "100px" }}>
                          <span
                            className={`badge ${
                              p.status?.toLowerCase() === "success"
                                ? "bg-success"
                                : p.status?.toLowerCase() === "pending"
                                  ? "bg-warning text-dark"
                                  : "bg-danger"
                            }`}
                          >
                            {p.status}
                          </span>
                        </td>
                        <td style={{ minWidth: "180px" }}>
                          {p.transactionId}{" "}
                          {p.transactionId && (
                            <i
                              className="fa-solid fa-copy ms-2"
                              style={{ cursor: "pointer" }}
                              onClick={() =>
                                handleCopy(p.transactionId, "Transaction ID")
                              }
                            ></i>
                          )}
                        </td>
                        <td style={{ minWidth: "200px" }}>
                          {dayjs(p.paymentDate).format("DD MMM YYYY, hh:mm A")}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            ) : (
              <p>No payments found for this user.</p>
            )}
          </div>
        </div>
      )}

{activeTab === "support" && (
  <div className="card border-0 mb-3">
    {loading ? (
      <div className="text-center p-3">Loading...</div>
    ) : (
      <div className="table-responsive rounded">
        <table className="table table-striped small mb-0">
          <thead className="table-dark">
            <tr>
              <th>ID</th>
              <th>Type</th>
              <th>Request ID</th>
              <th>Description</th>
              <th>Status</th>
              <th>Created At</th>
              <th>Updated At</th>
            </tr>
          </thead>
          <tbody>
            {supportRequest && supportRequest.length > 0 ? (
              supportRequest.map((s) => (
                <tr key={s.id}>
                  <td style={{ minWidth: "50px" }}>{s.id}</td>
                  <td style={{ minWidth: "120px" }}>{s.reqType}</td>
                  <td style={{ minWidth: "120px" }}>{s.reqId}</td>
                  <td style={{ minWidth: "400px" }}>
                    <div className="p-2 bg-light border rounded w-100">
                      {s.description}
                    </div>
                  </td>
                  <td style={{ minWidth: "100px" }}>
                    <span
                      className={`badge ${
                        s.status?.toLowerCase() === "open"
                          ? "bg-warning text-dark"
                          : s.status?.toLowerCase() === "closed"
                          ? "bg-success"
                          : "bg-info"
                      }`}
                    >
                      {s.status}
                    </span>
                  </td>
                  <td style={{ minWidth: "150px" }}>
                    {dayjs(s.createdAt).format("DD MMM YYYY hh:mm A")}
                  </td>
                  <td style={{ minWidth: "150px" }}>
                    {dayjs(s.updatedAt).format("DD MMM YYYY hh:mm A")}
                  </td>

                </tr>
              ))
            ) : (
              <tr>
                <td colSpan={8} className="text-center p-3">
                  No support requests found for this user.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    )}
  </div>
)}


    </div>
  );
}

export default UserDetails;
